const defaultData = [
  {
    color: 'primary',
    icon: 'ri-user-smile-line',
    text: 'white'
  },
  {
    color: 'secondary',
    icon: 'ri-check-double-line',
    text: 'white'
  },
  {
    color: 'success',
    icon: 'ri-notification-off-line',
    text: 'white'
  },
  {
    color: 'danger',
    icon: 'ri-error-warning-line',
    text: 'white'
  }
];

const dismissingData = [
  {
    color: 'warning',
    icon: 'ri-alert-line',
    text: 'white'
  },
  {
    color: 'info',
    icon: 'ri-airplay-line',
    text: 'white'
  },
  {
    color: 'light',
    icon: 'ri-airplay-line',
    text: 'body'
  },
  {
    color: 'dark',
    icon: 'ri-refresh-line',
    text: 'white'
  }
];
export { defaultData, dismissingData };
